+  private parseMarkdownEntry(
+    filePath: string,
+    content: string,
+    basePath: string
+  ): LegacyEntry | null {
+    // Extract frontmatter if present
+    const frontmatterMatch = content.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
