+/**
+ * Convenience function to create a migrator
+ */
+export function createMigrator(
+  target: AgentDBAdapter,
+  source: MigrationSource,
+  sourcePath: string,
+  options: Partial<MigrationConfig> = {},
+  embeddingGenerator?: EmbeddingGenerator
