+  }
+
+  // ==========================================================================
+  // Task Creation
+  // ==========================================================================
+
+  createTask(spec: TaskSpec): TaskDefinition {
+    const taskId: TaskId = `task-${Date.now()}-${++this.taskCounter}`;
+
+    const task: TaskDefinition = {
+      id: taskId,
+      type: spec.type,
+      title: spec.title,
+      description: spec.description,
+      assignedAgent: null,
+      status: 'pending',
+      priority: spec.priority ?? 'medium',
+      dependencies: spec.dependencies ?? [],
+      blockedBy: [],
+      metadata: {
+        domain: spec.domain,
+        phase: spec.phase,
+        estimatedDuration: spec.estimatedDuration ?? 0,
+        actualDuration: null,
+        retryCount: 0,
+        maxRetries: 3,
+        artifacts: [],
+        tags: spec.tags ?? []
+      },
+      createdAt: Date.now(),
+      updatedAt: Date.now(),
+      completedAt: null
+    };
