+    const index = task.dependencies.indexOf(dependsOn);
+    if (index > -1) {
+      task.dependencies.splice(index, 1);
+    }
+
+    this.dependencyGraph.get(taskId)?.delete(dependsOn);
+    this.dependentGraph.get(dependsOn)?.delete(taskId);
