+        const priorityOrder: Record<TaskPriority, number> = {
+          'critical': 0,
+          'high': 1,
+          'medium': 2,
+          'low': 3
+        };
+
+        const priorityDiff = priorityOrder[a.priority] - priorityOrder[b.priority];
