+      totalTasks: allTasks.length,
+      tasksByStatus,
+      tasksByPriority,
+      tasksByDomain,
+      averageQueueTime: totalQueueTime / (completedCount || 1),
+      averageExecutionTime: totalExecutionTime / (completedCount || 1),
+      throughput
+    };
+  }
+
+  // ==========================================================================
+  // Private Helpers
+  // ==========================================================================
+
+  private getTaskOrThrow(taskId: TaskId): TaskDefinition {
