+    while (stack.length > 0) {
+      const current = stack.pop()!;
+
+      if (current === taskId) {
+        return true;
+      }
+
+      if (visited.has(current)) {
+        continue;
+      }
+
+      visited.add(current);
+
+      const deps = this.dependencyGraph.get(current);
+      if (deps) {
